// // This module is designed to implement an 8-bit register that outputs the previous value of the data input when reset.
module register_8bit (
    input clk,
    input reset,
    input [7:0] d,
    output reg [7:0] q
);

    always @ (posedge clk or posedge reset) begin
        if (reset)
            q <= 8'b0;
        else
            q <= d;
    end

endmodule
